#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Define a large constant for infinity
const ll INF_NUM = 4e18; // Sufficiently large value given max costs are relatively small

// Helper function to solve the linear DP problem
// Finds min cost to get k_target non-adjacent peaks in the segment [L, R]
ll solveLinearDP(int L, int R, ll k_target, const std::vector<ll>& C) {
    if (k_target < 0) return INF_NUM;
    if (k_target == 0) return 0;
    if (L > R) return INF_NUM;

    int length = R - L + 1;
    if (k_target > (length + 1) / 2) return INF_NUM;

    // DP[i'][j][0]: Min cost for j peaks ending at relative index i', where element i = L+i' is skipped
    // DP[i'][j][1]: Min cost for j peaks ending at relative index i', where element i = L+i' is selected
    // We use i' up to length (1-based indexing for DP state size)
    std::vector<std::vector<std::vector<ll>>> dp(length + 1, 
        std::vector<std::vector<ll>>(k_target + 1, std::vector<ll>(2, INF_NUM))
    );

    // Base case: i' = 0 (corresponding to index L)
    dp[0][0][0] = 0;

    if (k_target >= 1) {
        // If we select the first element (index L)
        dp[0][1][1] = C[L];
    }

    for (int i_prime = 1; i_prime <= length; ++i_prime) {
        int i = L + i_prime - 1; // Actual index in nums/C

        for (ll j = 0; j <= k_target; ++j) {

            // State 0: i is skipped
            // Min cost is achieved by taking the best result from i-1 (whether selected or skipped)
            dp[i_prime][j][0] = std::min(dp[i_prime - 1][j][0], dp[i_prime - 1][j][1]);

            // State 1: i is selected (requires j >= 1)
            if (j >= 1) {
                // If i is selected, i-1 MUST have been skipped (state [0])
                ll prevCost = dp[i_prime - 1][j - 1][0];
                if (prevCost != INF_NUM) {
                     dp[i_prime][j][1] = prevCost + C[i];
                }
            }
        }
    }

    // The answer is the minimum cost when the last element R is either selected or skipped
    return std::min(dp[length][k_target][0], dp[length][k_target][1]);
}


long long solve(std::vector<long long> nums, long long k) {
    int N = nums.size();

    if (k == 0) return 0;

    // Maximum possible peaks is floor(N/2) if N is even, (N+1)/2 if N is odd, 
    // but since peaks must be separated by at least one non-peak, N/2 is a tight bound 
    // if we consider only alternating peaks/non-peaks.
    // For a circular array, the theoretical max is floor(N/2).
    if (k > N / 2) {
        return -1;
    }

    // Step 1: Calculate cost C[i] for each index i to be a peak
    std::vector<ll> C(N);
    for (int i = 0; i < N; ++i) {
        // Neighbors in circular array
        int L_idx = (i - 1 + N) % N;
        int R_idx = (i + 1) % N;

        ll required_val = std::max(nums[L_idx], nums[R_idx]) + 1;

        // Cost = max(0, required_val - nums[i])
        ll cost = std::max(0LL, required_val - nums[i]);
        C[i] = cost;
    }

    ll min_total_cost = INF_NUM;

    // Case 1: Index 0 is NOT selected (i.e., 0 is not a peak).
    // Solve linear DP on range [1, N-1] for target K peaks.
    ll cost1 = solveLinearDP(1, N - 1, k, C);
    min_total_cost = std::min(min_total_cost, cost1);


    // Case 2: Index 0 IS selected (0 is a peak).
    if (k >= 1) {
        ll cost0 = C[0];
        ll cost2;

        // If N is small (N=2 or N=3), the inner range [2, N-2] is empty or invalid for standard DP.
        if (N <= 3) {
            // If N=2 or N=3, and we selected 0, we need k-1 peaks from remaining elements.
            if (k == 1) {
                // N=2 or N=3, k=1. Index 0 is the peak. Cost is C[0]. Inner DP requires 0 peaks.
                cost2 = 0;
            } else {
                // If k > 1, we cannot achieve it with N<=3 if 0 is a peak and we require non-adjacent peaks.
                cost2 = INF_NUM; 
            }
        } else {
            // N >= 4. Standard DP applies on range [2, N-2] for target K-1 peaks.
            cost2 = solveLinearDP(2, N - 2, k - 1, C);
        }

        if (cost2 != INF_NUM) {
            min_total_cost = std::min(min_total_cost, cost0 + cost2);
        }
    }

    return min_total_cost == INF_NUM ? -1 : min_total_cost;
}

