        const R_idx = (i + 1) % N;

        const required_val = Math.max(nums[L_idx], nums[R_idx]) + 1;

        // Cost = max(0, required_val - nums[i])
        const cost = Math.max(0, required_val - nums[i]);
        C[i] = cost;
    }

