     * @param {number} L Start index (inclusive)
     * @param {number} R End index (inclusive)
     * @param {number} k_target Target number of peaks
     * @param {number[]} C_num Precalculated costs C_num[i]
     * @returns {number} Minimum cost, or INF_NUM.
     */
    const solveLinearDP_num = (L, R, k_target, C_num) => {
        if (k_target < 0) return INF_NUM;
        if (k_target === 0) return 0;
