    };


    let min_total_cost = INF_NUM;

    // Case 1: Index 0 is NOT selected. Range [1, N-1], Target K.
    let cost1 = solveLinearDP_num(1, N - 1, k, C);
    min_total_cost = Math.min(min_total_cost, cost1);


