 * Find min cost to get k_target peaks in range [L, R].
 * C is the precalculated cost array.
 * 
 * @param {number} L Start index (inclusive)
 * @param {number} R End index (inclusive)
 * @param {number} k_target Target number of peaks
 * @param {number[]} C Precalculated costs C[i]
 * @returns {bigint} Minimum cost, or Infinity equivalent.
 */
const solveLinearDP = (L, R, k_target, C) => {
    const N = C.length;
    const INF = BigInt(1e18); 

    if (k_target < 0) return INF;
    if (k_target === 0) return BigInt(0);
    if (L > R) {
        return INF; // Cannot achieve k_target > 0 peaks in an empty range
    }

    // We need DP tables indexed by relative position i' = i - L
    // Size: (R - L + 1) x (k_target + 1) x 2
    const length = R - L + 1;

    // DP[i'][j][0]: Min cost for j peaks ending at i, i skipped
    // DP[i'][j][1]: Min cost for j peaks ending at i, i selected

    // Using 2D arrays for space optimization if possible, but since R-L <= N, let's use 3D structure based on relative index i'

    // Initialize DP table
    let dp = Array(length + 1).fill(0).map(() => 
        Array(k_target + 1).fill(0).map(() => [INF, INF])
    );

    // Base case: i = L (relative index 0)
    // 1. L skipped (j=0): cost 0
    dp[0][0][0] = BigInt(0);

    // 2. L selected (j=1): cost C[L]
    if (k_target >= 1) {
        dp[0][1][1] = BigInt(C[L]);
    }

    // Iteration: i' from 1 to length - 1 (corresponding to actual index i = L + i')
    for (let i_prime = 1; i_prime < length; i_prime++) {
        const i = L + i_prime;

        for (let j = 0; j <= k_target; j++) {

            // State 0: i is skipped
            // Can transition from i-1 skipped or i-1 selected
            dp[i_prime][j][0] = minBigInt(dp[i_prime - 1][j][0], dp[i_prime - 1][j][1]);

            // State 1: i is selected (requires j >= 1)
            if (j >= 1) {
                // Must transition from i-1 skipped
                const prevCost = dp[i_prime - 1][j - 1][0];
                if (prevCost !== INF) {
