        const required_val = Math.max(nums[L_idx], nums[R_idx]) + 1;

        // Cost = max(0, required_val - nums[i])
        const cost = Math.max(0, required_val - nums[i]);
        C[i] = cost;
    }

    /**
     * Solves the linear DP problem: Find min cost to get k_target peaks in range [L, R].
     * @param {number} L Start index (inclusive)
     * @param {number} R End index (inclusive)
     * @param {number} k_target Target number of peaks
     * @param {number[]} C_num Precalculated costs C_num[i]
     * @returns {number} Minimum cost, or INF_NUM.
     */
    const solveLinearDP_num = (L, R, k_target, C_num) => {
        if (k_target < 0) return INF_NUM;
        if (k_target === 0) return 0;
        if (L > R) return INF_NUM;

        const length = R - L + 1;

        // DP[i'][j][0]: Min cost for j peaks ending at i, i skipped
        // DP[i'][j][1]: Min cost for j peaks ending at i, i selected
        let dp = Array(length + 1).fill(0).map(() => 
            Array(k_target + 1).fill(0).map(() => [INF_NUM, INF_NUM])
        );

        // Base case: i = L (relative index 0)
        dp[0][0][0] = 0;

        if (k_target >= 1) {
            dp[0][1][1] = C_num[L];
        }

        for (let i_prime = 1; i_prime < length; i_prime++) {
            const i = L + i_prime;

            for (let j = 0; j <= k_target; j++) {

                // State 0: i is skipped
                dp[i_prime][j][0] = Math.min(dp[i_prime - 1][j][0], dp[i_prime - 1][j][1]);

                // State 1: i is selected (requires j >= 1)
                if (j >= 1) {
                    const prevCost = dp[i_prime - 1][j - 1][0];
                    if (prevCost !== INF_NUM) {
                         dp[i_prime][j][1] = prevCost + C_num[i];
                    }
                }
            }
        }

        const final_i_prime = length - 1;
        return Math.min(dp[final_i_prime][k_target][0], dp[final_i_prime][k_target][1]);
    };


    let min_total_cost = INF_NUM;

    // Case 1: Index 0 is NOT selected. Range [1, N-1], Target K.
    let cost1 = solveLinearDP_num(1, N - 1, k, C);
    min_total_cost = Math.min(min_total_cost, cost1);


    // Case 2: Index 0 IS selected. Range [2, N-2], Target K-1.
    if (k >= 1) {
        let cost0 = C[0];
        let cost2;

        if (N <= 3) {
            // If N=2 or N=3, the inner range [2, N-2] is empty or invalid.
            // We need k-1=0 peaks from an empty set.
            if (k === 1) {
                cost2 = 0;
            } else {
                cost2 = INF_NUM; 
            }
        } else {
            // N >= 4. Standard DP applies.
            cost2 = solveLinearDP_num(2, N - 2, k - 1, C);
        }

        if (cost2 !== INF_NUM) {
            min_total_cost = Math.min(min_total_cost, cost0 + cost2);
        }
    }

    return min_total_cost === INF_NUM ? -1 : min_total_cost;
}
